const rows = $input.first().json.rows ?? [];

// チャネル別セッション集計
const channels = {};
for (const row of rows) {
  const ch = row.dimensionValues[0].value;
  const sessions = parseInt(row.metricValues[0].value) || 0;
  const conv = parseInt(row.metricValues[1].value) || 0;
  const rev = parseFloat(row.metricValues[2].value) || 0;
  if (!channels[ch]) channels[ch] = { sessions: 0, conv: 0, rev: 0 };
  channels[ch].sessions += sessions;
  channels[ch].conv += conv;
  channels[ch].rev += rev;
}

const topChannels = Object.entries(channels)
  .sort((a, b) => b[1].sessions - a[1].sessions)
  .slice(0, 5);

const total = topChannels.reduce((s, [, v]) => s + v.sessions, 0);
const totalConv = topChannels.reduce((s, [, v]) => s + v.conv, 0);
const totalRev = topChannels.reduce((s, [, v]) => s + v.rev, 0);

const lines = topChannels.map(([ch, v]) => {
  const pct = total ? Math.round(v.sessions / total * 100) : 0;
  return `  ${ch}: ${v.sessions}セッション (${pct}%) | CV:${v.conv}`;
});

const msg = [
  '📊 <b>KAIROX GA4 週次レポート</b>',
  `📅 過去7日間`,
  '',
  `👥 総セッション: <b>${total.toLocaleString()}</b>`,
  `✅ コンバージョン: <b>${totalConv}</b>`,
  `💰 収益: ¥<b>${Math.round(totalRev).toLocaleString()}</b>`,
  '',
  '📡 チャネル別:',
  ...lines,
].join('\n');

return [{ json: { message: msg } }];
